// Extract parameters from POST body
const body = msg.payload || {};
const systemName = msg.req.params.systemName;

const codec_ip = body.codec_ip;
const codec_auth = body.codec_auth;
const zbx_host = body.zbx_host || systemName;

// Validate required fields
const missing = [];
if (!codec_ip) missing.push('codec_ip');
if (!codec_auth) missing.push('codec_auth');

if (missing.length > 0) {
    msg.statusCode = 400;
    msg.payload = { error: `Missing required fields: ${missing.join(', ')}` };
    node.error(`Validation failed: missing ${missing.join(', ')}`, msg);
    return [null, msg];
}

// Store validated params for downstream nodes
msg.testParams = {
    systemName,
    codec_ip,
    codec_auth,
    zbx_host
};

// Send 202 Accepted
msg.statusCode = 202;
msg.payload = { accepted: true, system: systemName };

return [msg, msg];

const jsxapi = require('jsxapi');

const { systemName, codec_ip, codec_auth, zbx_host } = msg.testParams;
const [username, password] = Buffer.from(codec_auth, 'base64').toString().split(':');
const started = Date.now();
const events = [];

function log(type, data) {
    events.push({ ts: Date.now(), type, data });
}

let xapi;
try {
    // Connect to codec via WebSocket
    xapi = await jsxapi.connect(`wss://${codec_ip}`, {
        username,
        password
    });
    log('connected', { codec_ip });

    // Subscribe to audio diagnostic events before starting the test
    xapi.event.on('Audio Diagnostics', (evt) => {
        log('audio_diag_event', evt);
    });

    // Step 1: Check occupancy
    const presence = await xapi.status.get('RoomAnalytics PeoplePresence');
    log('occupancy_check', { presence });

    if (presence === 'Yes') {
        await xapi.close();
        log('skipped', 'Room occupied');
        msg.result = {
            system: systemName,
            zbx_host,
            status: 'skipped_occupied',
            events,
            audio: { channels_passed: 0, channels_total: 0 },
            display: { connected: 0, edid_ok: 0, power_ok: 0 },
            duration_ms: Date.now() - started
        };
        return msg;
    }

    // Step 2: Run audio diagnostics
    // This plays an impulse through each speaker and measures the response
    // on every microphone, validating both speakers and mics in one shot.
    await xapi.command('Audio Diagnostics Start');
    log('audio_diag_started', null);

    // Wait for diagnostics to complete (typically 10-15 seconds)
    await new Promise(resolve => setTimeout(resolve, 15000));

    // Step 3: Read diagnostic results
    let diagResults;
    try {
        diagResults = await xapi.status.get('Audio Diagnostics');
        log('audio_diag_result', diagResults);
    } catch (err) {
        log('audio_diag_error', err.message);
        diagResults = null;
    }

    // Step 4: Read display status
    let videoOutput;
    try {
        videoOutput = await xapi.status.get('Video Output');
        log('display_status', videoOutput);
    } catch (err) {
        log('display_error', err.message);
        videoOutput = null;
    }

    // Disconnect
    await xapi.close();
    log('disconnected', null);

    // --- Evaluate results ---

    // Parse audio diagnostic results
    let audio = { channels_passed: 0, channels_total: 0 };
    if (diagResults) {
        // The structure varies by firmware but typically:
        // diagResults is an object/array of channel results
        // Each channel has a Result field: 'Passed' or 'Failed'
        const channels = Array.isArray(diagResults) ? diagResults : 
                         diagResults.Channel ? (Array.isArray(diagResults.Channel) ? diagResults.Channel : [diagResults.Channel]) :
                         [];
        audio.channels_total = channels.length;
        audio.channels_passed = channels.filter(ch => {
            const result = ch.Result || ch.result || '';
            return result === 'Passed' || result === 'Pass';
        }).length;
    }

    // Parse display status
    let display = { connected: 0, edid_ok: 0, power_ok: 0 };
    if (videoOutput) {
        const connectors = Array.isArray(videoOutput.Connector) ? videoOutput.Connector :
                           videoOutput.Connector ? [videoOutput.Connector] :
                           Array.isArray(videoOutput) ? videoOutput : [];
        display.connected = connectors.filter(c => {
            const connected = c.Connected || c.connected || '';
            return connected === 'True' || connected === 'true' || connected === true;
        }).length;
        display.edid_ok = connectors.every(c => {
            if (!c.Connected || c.Connected !== 'True') return true; // skip disconnected
            return c.EDID && c.EDID !== 'Unknown';
        }) ? 1 : 0;
        // Power state may not be available on all connectors
        display.power_ok = connectors.some(c => {
            const cs = c.ConnectedDevice || {};
            return cs.PowerStatus === 'On' || cs.Status === 'On';
        }) ? 1 : 0;
    }

    // Determine overall status
    let status = 'passed';
    if (audio.channels_total > 0 && audio.channels_passed < audio.channels_total) {
        status = 'failed';
    }
    if (display.connected > 0 && display.edid_ok === 0) {
        status = 'failed';
    }

    msg.result = {
        system: systemName,
        zbx_host,
        status,
        events,
        audio,
        display,
        duration_ms: Date.now() - started
    };

} catch (err) {
    // Ensure we always try to close the connection
    if (xapi) {
        try { await xapi.close(); } catch (e) { /* ignore */ }
    }
    log('error', err.message);

    msg.result = {
        system: systemName,
        zbx_host,
        status: 'error',
        error: err.message,
        events,
        audio: { channels_passed: 0, channels_total: 0 },
        display: { connected: 0, edid_ok: 0, power_ok: 0 },
        duration_ms: Date.now() - started
    };
}

return msg;

const r = msg.result;
const ts = Math.floor(Date.now() / 1000);
const host = r.zbx_host;

// Build history.push item array
const items = [
    { host, key: 'og.synth.health.status', value: r.status, clock: ts, ns: 0 },
    { host, key: 'og.synth.health.duration_ms', value: String(r.duration_ms), clock: ts, ns: 0 },
    { host, key: 'og.synth.health.log', value: JSON.stringify(r.events), clock: ts, ns: 0 },
    { host, key: 'og.synth.health.audio.channels_passed', value: String(r.audio.channels_passed), clock: ts, ns: 0 },
    { host, key: 'og.synth.health.audio.channels_total', value: String(r.audio.channels_total), clock: ts, ns: 0 },
    { host, key: 'og.synth.health.display.connected', value: String(r.display.connected), clock: ts, ns: 0 },
    { host, key: 'og.synth.health.display.edid_ok', value: String(r.display.edid_ok), clock: ts, ns: 0 },
    { host, key: 'og.synth.health.display.power_ok', value: String(r.display.power_ok), clock: ts, ns: 0 }
];

// Build JSON-RPC request for Zabbix history.push API
const apiUrl = env.get('ZABBIX_API_URL') || global.get('ZABBIX_API_URL') || 'http://zabbix-web:8080/api_jsonrpc.php';
const apiToken = env.get('ZABBIX_API_TOKEN') || global.get('ZABBIX_API_TOKEN') || '';

msg.url = apiUrl;
msg.headers = { 'Content-Type': 'application/json-rpc' };
msg.payload = {
    jsonrpc: '2.0',
    method: 'history.push',
    params: items,
    auth: apiToken,
    id: 1
};

// Keep result for debug
msg.result = r;

return msg;

// If we don't already have a result (error outside the test function),
// build a minimal one so we still report something to Zabbix.
if (!msg.result) {
    const params = msg.testParams || {};
    msg.result = {
        system: params.systemName || 'unknown',
        zbx_host: params.zbx_host || 'unknown',
        status: 'error',
        error: msg.error ? msg.error.message : 'Unknown error',
        events: [],
        audio: { channels_passed: 0, channels_total: 0 },
        display: { connected: 0, edid_ok: 0, power_ok: 0 },
        duration_ms: 0
    };
}

return msg;
